import{_ as a,o as s,c as l,a5 as t}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling）","tags":["power-electronics"],"status":"learning","summary":"脉宽调制（pulse-width modulation / PWM）是用固定开关频率下的导通时间比例来控制功率开关。这个比例叫占空比（duty cycle / D）。"},"headers":[],"relativePath":"content/power/concepts/pwm-sampling.md","filePath":"content/power/concepts/pwm-sampling.md","lastUpdated":1782835746000}'),e={name:"content/power/concepts/pwm-sampling.md"};function p(n,i,o,h,r,d){return s(),l("div",null,[...i[0]||(i[0]=[t(`<h1 id="概念-脉宽调制-pulse-width-modulation-pwm-与模数转换器采样-analog-to-digital-converter-adc-sampling" tabindex="-1">概念：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling） <a class="header-anchor" href="#概念-脉宽调制-pulse-width-modulation-pwm-与模数转换器采样-analog-to-digital-converter-adc-sampling" aria-label="Permalink to &quot;概念：脉宽调制（pulse-width modulation / PWM）与模数转换器采样（analog-to-digital converter / ADC sampling）&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>脉宽调制（pulse-width modulation / PWM）是用固定开关频率下的导通时间比例来控制功率开关。这个比例叫占空比（duty cycle / D）。</p><p>模数转换器采样（analog-to-digital converter / ADC sampling）是把电压、电流等模拟量在某个时刻转换成数字量，交给控制中断服务程序（control interrupt service routine / control ISR）计算下一次控制输出。</p><p>本节只讲一个点：<strong>PWM 决定功率级什么时候切换，ADC 决定固件在什么时候“看见”功率级。</strong></p><h2 id="_2-ups-为什么需要它" tabindex="-1">2. UPS 为什么需要它 <a class="header-anchor" href="#_2-ups-为什么需要它" aria-label="Permalink to &quot;2. UPS 为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）控制软件不是连续观察电路，而是在固定时刻采样，再在固定中断里计算。</p><p>如果采样时刻不合适，固件可能看到：</p><ul><li>开关噪声尖峰，而不是真实平均电流。</li><li>电感电流谷底，误以为电流太小或进入异常状态。</li><li>控制延迟增大，导致电压环或电流环相位裕度变差。</li></ul><p>所以读 UPS C 语言工程时，必须看懂 PWM 更新事件、ADC 触发事件和控制 ISR 的时间关系。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>Boost 开关导通时，电感电流上升；开关关断时，电感电流下降。电流波形不是平滑直线，而是带有开关纹波。</p><p>ADC 如果刚好在开关跳变附近采样，就容易采到尖峰、振铃或驱动噪声。工程上常把采样点放在相对安静的位置，例如关断后经过一小段延时，或者电流纹波较稳定的位置。</p><p>这不是“采样越快越好”的问题，而是“在正确时刻采样”的问题。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>开关周期：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ts = 1 / fsw</span></span></code></pre></div><p>导通时间：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ton = D * Ts</span></span></code></pre></div><p>采样时刻可以用周期内相位表示：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>t_sample = (n + sample_phase) * Ts + sample_delay</span></span></code></pre></div><p>其中：</p><ul><li><code>fsw</code>：开关频率（switching frequency）。</li><li><code>Ts</code>：开关周期（switching period）。</li><li><code>D</code>：占空比（duty cycle / D）。</li><li><code>sample_phase</code>：采样相位，0.8 表示每个周期 80% 位置。</li><li><code>sample_delay</code>：采样延迟，用来避开开关边沿后的噪声。</li></ul><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>使用脚本：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/python/boost_pwm_sampling.py</span></span></code></pre></div><p>图中有三类信息：</p><ul><li>PWM 载波（PWM carrier）与占空比命令。</li><li>开关状态（switch state）。</li><li>电感电流（inductor current）与 ADC 采样点。</li></ul><p>观察重点不是输出电压，而是采样点落在电流纹波的哪个位置。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>在 C 语言工程里，这个概念通常分散在几个文件中：</p><ul><li>PWM 初始化：设置频率、计数模式、比较值和更新事件。</li><li>ADC 初始化：设置触发源、采样通道、采样时间和转换序列。</li><li>控制 ISR：读取 ADC 结果，计算控制器，更新下一周期 PWM 占空比。</li><li>保护逻辑：判断采样值是否越界，是否需要关断 PWM 或进入故障状态。</li></ul><p>你读代码时要追问：这个 ADC 值对应的是哪个 PWM 周期、哪个相位、哪个物理量？</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：ADC 采样越快越好。<br> 正确理解：采样频率和采样相位都重要。采在开关噪声上，快也没用。</p></li><li><p>错误理解：PWM 占空比一更新，输出马上按新值变化。<br> 正确理解：很多定时器有影子寄存器（shadow register），新占空比要等更新事件才生效。</p></li><li><p>错误理解：控制 ISR 里读到的电流就是“当前连续真实电流”。<br> 正确理解：它是某个采样时刻的离散值，带有采样延迟、滤波延迟和量化误差。</p></li><li><p>错误理解：仿真只要画平均值就够了。<br> 正确理解：采样点和开关纹波的位置关系，必须看时序图才能理解。</p></li></ul><h2 id="_8-一个仿真任务" tabindex="-1">8. 一个仿真任务 <a class="header-anchor" href="#_8-一个仿真任务" aria-label="Permalink to &quot;8. 一个仿真任务&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_pwm_sampling.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_pwm_sampling.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_pwm_sampling.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sample</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">phase </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_pwm_sampling_phase_02.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_pwm_sampling.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sample</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">phase </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.8</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_pwm_sampling_phase_08.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察红色 ADC 采样点落在电感电流纹波的哪个位置，并记录采样相位、采样延迟、采样电流值和开关状态。</p><h2 id="_9-验收标准" tabindex="-1">9. 验收标准 <a class="header-anchor" href="#_9-验收标准" aria-label="Permalink to &quot;9. 验收标准&quot;">​</a></h2><ul><li>能解释 PWM、ADC、控制 ISR 三者的先后关系。</li><li>能用 <code>Ts = 1 / fsw</code> 和 <code>Ton = D * Ts</code> 计算周期和导通时间。</li><li>能在 <code>simulations/results/boost_pwm_sampling.png</code> 上指出 ADC 采样点落在电感电流纹波的哪个位置。</li><li>能解释为什么采在开关边沿附近可能不可靠。</li><li>能把仿真图转换成一个具体的 C 工程代码阅读问题。</li></ul><h2 id="_10-复盘问题" tabindex="-1">10. 复盘问题 <a class="header-anchor" href="#_10-复盘问题" aria-label="Permalink to &quot;10. 复盘问题&quot;">​</a></h2><ul><li>打开 <code>simulations/results/boost_pwm_sampling.png</code>，红色 ADC 采样点落在电感电流的上升段还是下降段？</li><li>如果 <code>fsw = 20 kHz</code>，一个开关周期是多少微秒？<code>D = 0.45</code> 时导通时间是多少微秒？</li><li>如果把采样点放在开关翻转边沿附近，固件可能读到什么问题？</li></ul><h2 id="_11-导师问题" tabindex="-1">11. 导师问题 <a class="header-anchor" href="#_11-导师问题" aria-label="Permalink to &quot;11. 导师问题&quot;">​</a></h2><ul><li>我用 <code>boost_pwm_sampling.py</code> 看到 ADC 采样点放在每周期 80% 位置。公司 Boost 或功率因数校正（power factor correction / PFC）电流采样通常放在 PWM 周期的哪个相位，为什么？</li><li>如果控制 ISR 读取的是上一个 PWM 周期的 ADC 结果，公司代码里通常如何标注或处理这个一拍延迟？</li><li>公司平台的 PWM 占空比更新是立即生效，还是通过影子寄存器在更新事件生效？我应该从哪个初始化文件确认？</li></ul>`,45)])])}const u=a(e,[["render",p]]);export{k as __pageData,u as default};
